        val request = MAPPER.readValue("{\"max_tokens\":256,\"messages\":[{\"content\":\"What is the weather in London?\",\"role\":\"user\"}],\"model\":\"anthropic/claude-3-5-sonnet-20241022\",\"tool_choice\":\"auto\",\"tools\":[{\"function\":{\"description\":\"Get the current weather for a given location\",\"name\":\"get_weather\",\"parameters\":{\"properties\":{\"location\":{\"description\":\"The city and country, e.g. London, UK\",\"type\":\"string\"},\"unit\":{\"description\":\"The temperature unit to use\",\"enum\":[\"celsius\",\"fahrenheit\"],\"type\":\"string\"}},\"required\":[\"location\"],\"type\":\"object\"}},\"type\":\"function\"}]}", ChatCompletionRequest::class.java)
        val client = LiterLlm.createClient(apiKey = "test-key", baseUrl = System.getenv("MOCK_SERVER_URL") + "/fixtures/anthropic_tool_calling")
        val result = client.chat(request)
        assertEquals(1, result.choices().size, "expected exactly 1 elements")
        assertFalse(result.choices().first().message().toolCalls().orEmpty().isEmpty(), "expected non-empty value")
        assertEquals("get_weather", result.choices().first().message().toolCalls().first().function().name().trim())
        assertEquals("tool_calls", result.choices().first().finishReason().orEmpty().getValue().trim())
        client.close()
    }

